<!-- App.vue -->

<template>
  <div class="container">
    <h1 class="title">Custom CSS Generator</h1>
    <div v-for="(block, index) in cssBlocks" :key="index" class="block">
      <h2 class="subtitle">{{ getCssFileName(index) }}</h2>
      <textarea v-model="block.content" class="textarea" placeholder="Enter CSS block"></textarea>
      <label class="checkbox">
        <input type="checkbox" v-model="block.isSelected"> Apply CSS
      </label>
    </div>
    <button @click="generateCustomCss" class="button is-primary">Generate Custom CSS</button>
    <textarea v-model="customCss" readonly class="textarea result"></textarea>
  </div>
</template>

<script>
import axios from 'axios';

export default {
  data() {
    return {
      cssBlocks: [],
      customCss: '',
      cssFileNames: [],
      owner: 'kanade',
      repo: 'misskey-css',
    };
  },
  mounted() {
    // Load all external CSS on page load
    this.loadAllExternalCss();
  },
  methods: {
    async loadAllExternalCss() {
      try {
        const response = await axios.get(`https://api.github.com/repos/${this.owner}/${this.repo}/contents/assets/css`);
        const cssFiles = response.data;

        const cssFilesFiltered = cssFiles.filter(file => file.name.endsWith('.css'));

        for (let i = 0; i < cssFilesFiltered.length; i++) {
          const cssPath = `/assets/css/${cssFilesFiltered[i].name}`;
          const rawUrl = `https://raw.githubusercontent.com/${this.owner}/${this.repo}/main${cssPath}`;
          
          try {
            const cssResponse = await axios.get(rawUrl);
            this.cssBlocks[i] = { content: cssResponse.data, isSelected: false };

            const fileNameWithoutPrefixAndExtension = cssFilesFiltered[i].name.replace(/^\d+_/, '').replace(/\.[^.]+$/, '');
            this.cssFileNames[i] = fileNameWithoutPrefixAndExtension;
          } catch (error) {
            console.error('Error loading external CSS:', error);
          }
        }
      } catch (error) {
        console.error('Error loading external CSS list:', error);
      }
    },
    generateCustomCss() {
      this.customCss = this.cssBlocks
        .filter(block => block.isSelected)
        .map(block => block.content)
        .join('\n\n'); // Add new lines between blocks if needed
    },
    getCssFileName(index) {
      return this.cssFileNames[index] || 'Unnamed CSS';
    },
  },
};
</script>

<style>
/* Bulma styles */
@import 'bulma/css/bulma.css';

/* Custom styles */
.block {
  margin-bottom: 1em;
}

.result {
  margin-top: 1em;
}

/* Mobile styles */
@media screen and (max-width: 768px) {
  .container {
    margin: auto 16px;
  }
  .block {
    display: block;
  }
}
